import { app, BrowserWindow, type IpcMainInvokeEvent, nativeImage } from "electron";
import { writeFileSync } from "fs";
import { tmpdir } from "os";
import { join } from "path";

const ICO_B64 = "";
const PNG_B64 = "";

const isMac = process.platform === "darwin";
const isWin = process.platform === "win32";

let enabled = false;
let icoPath: string | null = null;
let catImage: Electron.NativeImage | null = null;
let originalIcon: Electron.NativeImage | null = null;

function log(msg: string, err?: unknown) {
    console.error("[KittyLogo] " + msg, err ?? "");
}

function ensureAssets() {
    if (!catImage) {
        try {
            catImage = nativeImage.createFromDataURL("data:image/png;base64," + PNG_B64);
        } catch (e) {
            log("failed to decode png icon", e);
        }
    }
    if (isWin && !icoPath) {
        try {
            const file = join(tmpdir(), "kittycord-app-icon.ico");
            writeFileSync(file, Buffer.from(ICO_B64, "base64"));
            icoPath = file;
        } catch (e) {
            log("failed to write ico asset", e);
        }
    }
}

function setWindowIcon(win: Electron.BrowserWindow) {
    if (isMac || win.isDestroyed()) return;
    ensureAssets();
    try {
        if (isWin && icoPath) win.setIcon(icoPath);
        else if (catImage && !catImage.isEmpty()) win.setIcon(catImage);
    } catch (e) {
        log("setIcon failed", e);
    }
}

function applyToWindow(win: Electron.BrowserWindow) {
    if (!enabled) return;
    if (isMac) {
        ensureAssets();
        if (catImage && !catImage.isEmpty()) {
            try { app.dock?.setIcon(catImage); } catch (e) { log("dock setIcon failed", e); }
        }
        return;
    }
    setWindowIcon(win);
}

function applyToAll() {
    if (isMac) {
        ensureAssets();
        if (catImage && !catImage.isEmpty()) {
            try { app.dock?.setIcon(catImage); } catch (e) { log("dock setIcon failed", e); }
        }
        return;
    }
    for (const win of BrowserWindow.getAllWindows()) setWindowIcon(win);
}

function revertWindow(win: Electron.BrowserWindow) {
    if (win.isDestroyed()) return;
    try {
        if (originalIcon && !originalIcon.isEmpty()) win.setIcon(originalIcon);
        else (win.setIcon as (icon: unknown) => void)(null);
    } catch (e) {
        log("revert setIcon failed", e);
    }
}

function revertAll() {
    if (isMac) {
        try { (app.dock?.setIcon as ((icon: unknown) => void) | undefined)?.(null); } catch (e) { log("dock revert failed", e); }
        return;
    }
    for (const win of BrowserWindow.getAllWindows()) revertWindow(win);
}

function captureOriginal() {
    if (isMac || originalIcon) return;
    try {
        app.getFileIcon(process.execPath, { size: "large" })
            .then(img => { originalIcon = img; })
            .catch(() => { });
    } catch { }
}

app.on("browser-window-created", (_, win) => {
    win.once("ready-to-show", () => applyToWindow(win));
    win.on("show", () => applyToWindow(win));
    win.on("focus", () => applyToWindow(win));
    win.webContents.on("did-finish-load", () => applyToWindow(win));
});

try {
    if (app.isReady()) captureOriginal();
    else app.once("ready", captureOriginal);
} catch { }

export function enableAppIcon(_: IpcMainInvokeEvent) {
    captureOriginal();
    enabled = true;
    applyToAll();
}

export function disableAppIcon(_: IpcMainInvokeEvent) {
    enabled = false;
    revertAll();
}
